def main(raw_data, analysis_type):
    import json

    # 基础统计
    total_amount = sum(d.get('amount', 0) for d in raw_data)
    total_orders = len(raw_data)
    avg_amount = total_amount / total_orders if total_orders > 0 else 0

    # 按类别汇总
    by_category = {}
    for d in raw_data:
        cat = d.get('category', 'unknown')
        if cat not in by_category:
            by_category[cat] = {'amount': 0, 'count': 0}
        by_category[cat]['amount'] += d.get('amount', 0)
        by_category[cat]['count'] += 1

    # 排序
    sorted_cats = sorted(by_category.items(), key=lambda x: x[1]['amount'], reverse=True)

    return {
        'processed_data': {
            'total_amount': round(total_amount, 2),
            'total_orders': total_orders,
            'avg_amount': round(avg_amount, 2),
            'by_category': sorted_cats[:10]
        },
        'chart_config': {
            'type': 'bar',
            'data_key': 'by_category',
            'labels': [c[0] for c in sorted_cats[:10]],
            'values': [c[1]['amount'] for c in sorted_cats[:10]]
        }
    }

